import{_ as i,o as a,c as e,a2 as t}from"./chunks/framework.DRBHoC6Q.js";const u=JSON.parse('{"title":"CEO 现金流驾驶舱 V1.0 财务数据接入与产品对接说明","description":"","frontmatter":{},"headers":[],"relativePath":"CEO现金流驾驶舱V1.0_财务数据接入与标准模板对接说明.md","filePath":"CEO现金流驾驶舱V1.0_财务数据接入与标准模板对接说明.md","lastUpdated":1783323851000}'),n={name:"CEO现金流驾驶舱V1.0_财务数据接入与标准模板对接说明.md"};function s(r,l,p,d,o,h){return a(),e("div",null,[...l[0]||(l[0]=[t(`<h1 id="ceo-现金流驾驶舱-v1-0-财务数据接入与产品对接说明" tabindex="-1">CEO 现金流驾驶舱 V1.0 财务数据接入与产品对接说明 <a class="header-anchor" href="#ceo-现金流驾驶舱-v1-0-财务数据接入与产品对接说明" aria-label="Permalink to &quot;CEO 现金流驾驶舱 V1.0 财务数据接入与产品对接说明&quot;">​</a></h1><p>文档状态：对接讨论稿<br> 目标读者：AI 产品经理、财务/CFO、技术负责人<br> 本文目标：明确为什么当前需要开展财务数据对接、产品经理需要与财务确认什么，以及确认完成后应交付哪些材料。</p><h2 id="一、当前为什么需要开展数据对接" tabindex="-1">一、当前为什么需要开展数据对接 <a class="header-anchor" href="#一、当前为什么需要开展数据对接" aria-label="Permalink to &quot;一、当前为什么需要开展数据对接&quot;">​</a></h2><p>现有项目已经形成驾驶舱 Demo，并初步定义了现金、回款、支出、风险和待办等展示指标，但当前数据均为 Mock 数据。</p><p>要将 Demo 推进为真实可用的 V1.0，必须先解决这些指标依赖的原始数据从哪里来、如何进入系统、如何更新以及如何计算的问题。</p><p>当前文档中的“本月可用现金”“本月预计回款”“本月现金流缺口”等字段，属于驾驶舱展示指标或系统计算结果，不是 Excel 导入字段。完整链路应为：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>财务原始数据</span></span>
<span class="line"><span>→ 标准 Excel 模板</span></span>
<span class="line"><span>→ 上传、解析、校验和确认</span></span>
<span class="line"><span>→ 业务明细入库</span></span>
<span class="line"><span>→ 规则计算</span></span>
<span class="line"><span>→ 指标快照</span></span>
<span class="line"><span>→ 驾驶舱展示与 AI Tool 查询</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>如果不先明确数据接入规则，技术团队无法稳定完成：</p><ul><li>标准 Excel 模板；</li><li>数据库表结构；</li><li>Excel 解析和校验逻辑；</li><li>数据新增、更新和作废逻辑；</li><li>指标计算；</li><li>驾驶舱真实接口；</li><li>AI 数据查询 Tool。</li></ul><h2 id="二、本次对接的目标" tabindex="-1">二、本次对接的目标 <a class="header-anchor" href="#二、本次对接的目标" aria-label="Permalink to &quot;二、本次对接的目标&quot;">​</a></h2><p>本次对接不是建设完整财务 ERP，也不是要求财务提供完整账务、凭证和总账数据。</p><p>对接目标是：</p><blockquote><p>围绕 CEO 现金流经营研判，确定能够支撑 V1.0 核心指标的最小财务业务数据，并将其固化成由项目方提供的标准导入模板。</p></blockquote><p>产品经理需要和财务共同确认：</p><ol><li>财务当前是否掌握所需数据；</li><li>数据的真实业务含义和粒度；</li><li>数据之间如何关联；</li><li>哪些是原始事实，哪些由系统计算；</li><li>数据如何上传、更新、修正和发布；</li><li>财务是否能够持续按标准模板提供数据。</li></ol><h2 id="三、v1-0-驾驶舱问题与数据需求" tabindex="-1">三、V1.0 驾驶舱问题与数据需求 <a class="header-anchor" href="#三、v1-0-驾驶舱问题与数据需求" aria-label="Permalink to &quot;三、V1.0 驾驶舱问题与数据需求&quot;">​</a></h2><table tabindex="0"><thead><tr><th>驾驶舱问题</th><th>需要财务提供的数据</th></tr></thead><tbody><tr><td>现在有多少钱</td><td>账户余额快照</td></tr><tr><td>本月预计进多少钱</td><td>应收款、预计到账日期</td></tr><tr><td>本月已经进多少钱</td><td>实际回款记录</td></tr><tr><td>本月准备花多少钱</td><td>计划支出</td></tr><tr><td>管理费用还能花多少</td><td>预算及已占用金额</td></tr><tr><td>哪些款已经逾期</td><td>应收款、到期日、实际回款</td></tr><tr><td>谁需要处理</td><td>客户/业务与责任人关系</td></tr></tbody></table><p>V1.0 建议优先确认以下四类数据：</p><ol><li>现金余额；</li><li>应收款；</li><li>实际回款；</li><li>计划支出。</li></ol><p>预算和客户责任人关系可以同步确认；如果首期时间有限，可根据驾驶舱实际范围分批落地。</p><h2 id="四、产品经理需要与财务确认的内容" tabindex="-1">四、产品经理需要与财务确认的内容 <a class="header-anchor" href="#四、产品经理需要与财务确认的内容" aria-label="Permalink to &quot;四、产品经理需要与财务确认的内容&quot;">​</a></h2><h3 id="_4-1-现有数据情况" tabindex="-1">4.1 现有数据情况 <a class="header-anchor" href="#_4-1-现有数据情况" aria-label="Permalink to &quot;4.1 现有数据情况&quot;">​</a></h3><ul><li>财务目前有哪些 Excel 可以提供上述数据？</li><li>是否可以提供脱敏样表和样例数据？</li><li>每张表由谁维护、谁复核？</li><li>数据多久更新一次？</li><li>是否存在同一类数据由多人维护、格式不一致的情况？</li></ul><p>现有财务 Excel 只用于理解业务事实和数据现状。V1.0 最终应由项目方输出标准模板，不长期兼容各种历史表格格式。</p><h3 id="_4-2-每张表的业务含义" tabindex="-1">4.2 每张表的业务含义 <a class="header-anchor" href="#_4-2-每张表的业务含义" aria-label="Permalink to &quot;4.2 每张表的业务含义&quot;">​</a></h3><p>需要逐表确认：</p><ul><li>这张表解决什么业务问题？</li><li>每个 Sheet 的用途是什么？</li><li>一行数据代表什么：账户快照、应收事项、实际到账事件还是支出计划？</li><li>表中哪些是明细行，哪些是汇总行？</li><li>哪些字段由人工填写，哪些是 Excel 公式？</li></ul><h3 id="_4-3-字段定义" tabindex="-1">4.3 字段定义 <a class="header-anchor" href="#_4-3-字段定义" aria-label="Permalink to &quot;4.3 字段定义&quot;">​</a></h3><p>每个字段至少需要确认：</p><ul><li>中文名称；</li><li>业务定义；</li><li>示例值；</li><li>是否必填；</li><li>数据类型；</li><li>金额单位和币种；</li><li>日期口径；</li><li>允许值范围；</li><li>是否允许为空；</li><li>是原始事实还是计算结果。</li></ul><p>例如，“应收金额”必须确认是合同总金额、当期应收金额，还是当前未回余额。</p><h3 id="_4-4-唯一标识" tabindex="-1">4.4 唯一标识 <a class="header-anchor" href="#_4-4-唯一标识" aria-label="Permalink to &quot;4.4 唯一标识&quot;">​</a></h3><p>每类数据必须能唯一识别，否则系统无法判断重复、新增和更新。</p><p>需要确认：</p><ul><li>是否存在账户编号；</li><li>是否存在客户编号；</li><li>是否存在合同编号；</li><li>是否存在应收单号；</li><li>是否存在回款流水号；</li><li>是否存在支出计划编号；</li><li>如果当前没有唯一编号，财务能否在标准模板中补充？</li></ul><h3 id="_4-5-数据之间的关联" tabindex="-1">4.5 数据之间的关联 <a class="header-anchor" href="#_4-5-数据之间的关联" aria-label="Permalink to &quot;4.5 数据之间的关联&quot;">​</a></h3><p>需要确认主要业务关系：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户 → 合同/业务 → 应收事项 → 实际回款</span></span>
<span class="line"><span>部门/项目 → 预算 → 计划支出</span></span>
<span class="line"><span>客户/业务 → 责任人</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>重点问题包括：</p><ul><li>客户、合同、应收和回款通过什么编号关联？</li><li>一个合同是否包含多笔应收？</li><li>一笔应收是否允许分多次到账？</li><li>一笔回款是否可能对应多笔应收？</li><li>客户重名或名称变化时如何识别？</li><li>责任人变更后，历史记录是否保留原责任人？</li></ul><h3 id="_4-6-数据导入方式" tabindex="-1">4.6 数据导入方式 <a class="header-anchor" href="#_4-6-数据导入方式" aria-label="Permalink to &quot;4.6 数据导入方式&quot;">​</a></h3><p>每种模板都需要单独确认：</p><ul><li>每次上传是全量快照还是增量追加？</li><li>同一个文件能否重复上传？</li><li>已存在记录是忽略、报错还是更新？</li><li>新文件缺少旧记录时，是否代表旧记录作废？</li><li>数据属于哪个业务日期和账期？</li><li>补录历史数据后是否需要重算历史指标？</li></ul><p>不同数据类型的推荐方式如下：</p><table tabindex="0"><thead><tr><th>数据类型</th><th>推荐导入方式</th><th>唯一键示例</th></tr></thead><tbody><tr><td>现金余额</td><td>按日期追加；同账户同日期更新</td><td>账户编号 + 统计日期</td></tr><tr><td>应收款</td><td>按应收单号新增或更新</td><td>应收单号</td></tr><tr><td>实际回款</td><td>增量追加；重复流水号拒绝或忽略</td><td>回款流水号</td></tr><tr><td>计划支出</td><td>按计划编号新增或更新</td><td>支出计划编号</td></tr><tr><td>预算</td><td>按周期和预算维度更新</td><td>周期 + 部门/项目 + 科目</td></tr><tr><td>客户与责任人</td><td>按客户编号新增或更新</td><td>客户编号</td></tr></tbody></table><p>以上是技术推荐默认值，最终需要产品和财务结合实际业务确认。</p><h3 id="_4-7-字段修改规则" tabindex="-1">4.7 字段修改规则 <a class="header-anchor" href="#_4-7-字段修改规则" aria-label="Permalink to &quot;4.7 字段修改规则&quot;">​</a></h3><p>需要确认：</p><ul><li>哪些字段允许更新？</li><li>哪些数据确认后不能直接修改？</li><li>空单元格表示“不修改”，还是“清空原值”？</li><li>金额变化是直接覆盖，还是保留调整记录？</li><li>“已回款”等状态是否允许改回未回款？</li><li>已发布数据发现错误时如何更正？</li></ul><p>空值语义必须明确，避免误清空正式数据。</p><h3 id="_4-8-删除、作废和历史保留" tabindex="-1">4.8 删除、作废和历史保留 <a class="header-anchor" href="#_4-8-删除、作废和历史保留" aria-label="Permalink to &quot;4.8 删除、作废和历史保留&quot;">​</a></h3><p>建议不通过 Excel 中“缺少某行”来删除系统数据，而是采用明确的有效/作废状态。</p><p>需要确认：</p><ul><li>已发布数据能否删除？</li><li>应收取消后是删除还是作废？</li><li>错误回款如何冲销或更正？</li><li>已经参与历史指标计算的数据如何处理？</li><li>是否需要保留修改前后的版本？</li></ul><p>V1.0 推荐：正式数据不物理删除，使用作废或更正，并保留追踪记录。</p><h3 id="_4-9-校验规则" tabindex="-1">4.9 校验规则 <a class="header-anchor" href="#_4-9-校验规则" aria-label="Permalink to &quot;4.9 校验规则&quot;">​</a></h3><p>产品和财务需要区分“阻止发布的错误”和“允许人工确认的警告”。</p><p>建议确认：</p><ul><li>必填字段缺失；</li><li>编号重复；</li><li>客户或责任人不存在；</li><li>金额格式错误或小于零；</li><li>已回金额超过应收金额；</li><li>日期先后矛盾；</li><li>账期不匹配；</li><li>状态与金额矛盾；</li><li>跨表关联失败。</li></ul><h3 id="_4-10-数据确认与发布" tabindex="-1">4.10 数据确认与发布 <a class="header-anchor" href="#_4-10-数据确认与发布" aria-label="Permalink to &quot;4.10 数据确认与发布&quot;">​</a></h3><p>上传不等于正式入库。需要确认：</p><ul><li>谁负责核对解析结果？</li><li>什么条件下数据可以发布？</li><li>是否允许只发布部分正确行？</li><li>发布失败是否整批回滚？</li><li>错误批次如何作废？</li><li>新数据发布后是否立即刷新驾驶舱？</li></ul><p>V1.0 推荐采用：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>上传 → 解析 → 校验 → 人工确认 → 整批发布 → 指标重算</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>一个批次整体成功或整体失败，避免驾驶舱读取到半批数据。</p><h2 id="五、原始数据与系统计算的边界" tabindex="-1">五、原始数据与系统计算的边界 <a class="header-anchor" href="#五、原始数据与系统计算的边界" aria-label="Permalink to &quot;五、原始数据与系统计算的边界&quot;">​</a></h2><p>财务负责提供原始业务事实，不应人工填写系统可以确定性计算的结果。</p><h3 id="财务提供" tabindex="-1">财务提供 <a class="header-anchor" href="#财务提供" aria-label="Permalink to &quot;财务提供&quot;">​</a></h3><ul><li>现金余额；</li><li>应收金额；</li><li>实际回款金额；</li><li>约定到账日期；</li><li>预计到账日期；</li><li>计划支出；</li><li>预算金额；</li><li>客户、业务和责任人关系。</li></ul><h3 id="系统计算" tabindex="-1">系统计算 <a class="header-anchor" href="#系统计算" aria-label="Permalink to &quot;系统计算&quot;">​</a></h3><ul><li>未回金额；</li><li>逾期天数；</li><li>回款风险等级；</li><li>本月预计回款；</li><li>本月实际回款；</li><li>本月计划支出；</li><li>管理费用可用额度；</li><li>现金流缺口；</li><li>今日待办和升级状态。</li></ul><p>系统计算公式、阈值和口径需要由财务/CFO 确认，技术团队负责实现和版本管理。</p><h2 id="六、标准模板形成路径" tabindex="-1">六、标准模板形成路径 <a class="header-anchor" href="#六、标准模板形成路径" aria-label="Permalink to &quot;六、标准模板形成路径&quot;">​</a></h2><p>建议按以下流程推进：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>财务提供现有脱敏样表和业务说明</span></span>
<span class="line"><span>→ 产品确认 V1.0 需要哪些数据</span></span>
<span class="line"><span>→ 技术抽象业务实体、标准字段和关联关系</span></span>
<span class="line"><span>→ 项目方发布标准模板初稿</span></span>
<span class="line"><span>→ 财务试填</span></span>
<span class="line"><span>→ 产品、财务和技术联合评审</span></span>
<span class="line"><span>→ 修订并冻结模板 V1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>标准模板应由项目方提供，财务按模板填写。现有财务表不是长期接口，只是设计标准模板的参考输入。</p><h2 id="七、职责分工" tabindex="-1">七、职责分工 <a class="header-anchor" href="#七、职责分工" aria-label="Permalink to &quot;七、职责分工&quot;">​</a></h2><h3 id="产品经理负责" tabindex="-1">产品经理负责 <a class="header-anchor" href="#产品经理负责" aria-label="Permalink to &quot;产品经理负责&quot;">​</a></h3><ul><li>确认 V1.0 要回答的经营问题；</li><li>组织财务访谈；</li><li>梳理业务流程和异常处理方式；</li><li>确认哪些数据和规则进入 V1.0；</li><li>形成业务待确认项并推动闭环；</li><li>组织模板试填和联合评审。</li></ul><h3 id="财务-cfo-负责" tabindex="-1">财务/CFO 负责 <a class="header-anchor" href="#财务-cfo-负责" aria-label="Permalink to &quot;财务/CFO 负责&quot;">​</a></h3><ul><li>提供现有脱敏样表；</li><li>解释字段业务含义和数据粒度；</li><li>确认所需数据能否持续提供；</li><li>确认唯一标识和业务关联依据；</li><li>确认计算公式、阈值和复核规则；</li><li>按标准模板试填并反馈；</li><li>最终确认模板和财务口径。</li></ul><h3 id="技术负责人负责" tabindex="-1">技术负责人负责 <a class="header-anchor" href="#技术负责人负责" aria-label="Permalink to &quot;技术负责人负责&quot;">​</a></h3><ul><li>将业务要求转换为数据模型；</li><li>设计标准模板结构和字段规范；</li><li>设计唯一键、数据库约束和关联关系；</li><li>设计增量、更新、作废和版本策略；</li><li>设计解析、校验、确认和发布流程；</li><li>设计指标计算、API 和 AI Tool；</li><li>明确技术风险及无法实现的业务要求。</li></ul><h2 id="八、预期交付物" tabindex="-1">八、预期交付物 <a class="header-anchor" href="#八、预期交付物" aria-label="Permalink to &quot;八、预期交付物&quot;">​</a></h2><p>本轮对接完成后，需要形成以下材料：</p><ol><li>《V1.0 数据来源与样表清单》；</li><li>《标准 Excel 模板 V1》；</li><li>《字段数据字典》；</li><li>《业务实体及关联关系说明》；</li><li>《数据导入、更新与发布规则》；</li><li>《数据校验规则清单》；</li><li>《指标与来源数据映射表》；</li><li>《待确认问题及责任人清单》；</li><li>一套可用于技术联调的脱敏样例数据。</li></ol><h2 id="九、完成标准" tabindex="-1">九、完成标准 <a class="header-anchor" href="#九、完成标准" aria-label="Permalink to &quot;九、完成标准&quot;">​</a></h2><p>以下问题均得到明确答案后，本轮数据对接才算完成：</p><ul><li>[ ] V1.0 需要接入哪些类型的数据？</li><li>[ ] 每种数据由哪个标准模板承载？</li><li>[ ] 每张表的一行代表什么？</li><li>[ ] 每个字段的业务含义和格式是什么？</li><li>[ ] 每类数据的唯一标识是什么？</li><li>[ ] 不同数据之间如何关联？</li><li>[ ] 每种模板是全量、快照还是增量导入？</li><li>[ ] 重复、修改、空值和作废如何处理？</li><li>[ ] 哪些错误阻止发布，哪些仅提示？</li><li>[ ] 谁负责核对和确认发布？</li><li>[ ] 哪些字段由财务提供，哪些由系统计算？</li><li>[ ] 数据变化会触发哪些指标重算？</li><li>[ ] 财务已使用标准模板完成至少一次试填。</li></ul><h2 id="十、关键结论" tabindex="-1">十、关键结论 <a class="header-anchor" href="#十、关键结论" aria-label="Permalink to &quot;十、关键结论&quot;">​</a></h2><p>本项目的数据接入不是对财务历史 Excel 做无限适配，而是基于实际业务和驾驶舱目标，由项目方制定标准模板。</p><p>产品经理本轮对接的核心任务不是收集若干 Excel 文件，而是推动财务事实、字段口径、关联关系和数据更新规则形成可确认、可执行的标准。</p><p>技术团队将在这些标准确认后，完成数据库表结构、Excel 解析、数据校验、指标计算、驾驶舱接口和 AI Tool 的正式设计。</p>`,93)])])}const b=i(n,[["render",s]]);export{u as __pageData,b as default};
